import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { Invoice, InvoiceStatus } from '../../core/models';

@Component({
  selector: 'app-invoice-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './invoice-detail.component.html',
})
export class InvoiceDetailComponent {
  private route = inject(ActivatedRoute);

  invoices = signal<Invoice[]>([
    {
      id: 'inv1',
      number: 'INV-3001',
      salesOrderId: 'so4',
      customerId: 'c1',
      customerName: 'Northwind Traders',
      status: 'open',
      issuedAt: '2026-07-02',
      paidAt: null,
      lines: [
        { id: 'il1', productId: 'p8', productName: 'Proximity Sensor', sku: 'SEN-200', qty: 15, unitPrice: 49.0 },
      ],
      total: 735,
    },
    {
      id: 'inv2',
      number: 'INV-3002',
      salesOrderId: 'so9',
      customerId: 'c2',
      customerName: 'Contoso Ltd',
      status: 'open',
      issuedAt: '2026-07-05',
      paidAt: null,
      lines: [
        { id: 'il2', productId: 'p7', productName: 'Control Panel', sku: 'PNL-100', qty: 15, unitPrice: 320.0 },
        { id: 'il3', productId: 'p5', productName: 'Copper Wire 14AWG', sku: 'WIR-014', qty: 12, unitPrice: 23.79 },
      ],
      total: 5085.5,
    },
    {
      id: 'inv3',
      number: 'INV-3000',
      salesOrderId: 'so8',
      customerId: 'c3',
      customerName: 'Fabrikam Inc',
      status: 'paid',
      issuedAt: '2026-06-28',
      paidAt: '2026-07-01',
      lines: [
        { id: 'il4', productId: 'p3', productName: 'PVC Pipe 50mm', sku: 'PIP-050', qty: 40, unitPrice: 7.5 },
        { id: 'il5', productId: 'p1', productName: 'Steel Bolt M8', sku: 'STL-001', qty: 100, unitPrice: 1.2 },
      ],
      total: 420,
    },
  ]);

  id = this.route.snapshot.paramMap.get('id');

  invoice = computed(() => this.invoices().find((i) => i.id === this.id) ?? this.invoices()[0]);

  statusBadge(s: InvoiceStatus): string {
    return s === 'paid' ? 'badge-success' : 'badge-warning';
  }

  print(): void {
    window.print();
  }

  markPaid(): void {
    const current = this.invoice();
    if (current.status !== 'open') {
      return;
    }
    this.invoices.update((list) =>
      list.map((i) =>
        i.id === current.id ? { ...i, status: 'paid' as InvoiceStatus, paidAt: '2026-07-12' } : i,
      ),
    );
  }
}
